'use client';

import { useState, useEffect } from 'react';
import Link from 'next/link';
import Image from 'next/image';
import { orderApi, refundApi } from '@/lib/api';
import { useSocket } from '@/context/SocketContext';

// Returns hours remaining in 48h refund window, or null if unknown
function getRefundHoursLeft(order: any): number | null {
  if (!order.deliveredAt) return null;
  const ms = new Date(order.deliveredAt).getTime() + 48 * 60 * 60 * 1000 - Date.now();
  return Math.max(0, ms / (1000 * 60 * 60));
}

const statusSteps = [
  { key: 'NOT_STARTED', label: 'Not Started', icon: 'ΓÅ│' },
  { key: 'STARTED', label: 'Started', icon: '≡ƒÜÇ' },
  { key: 'IN_PROCESS', label: 'In Process', icon: 'ΓÜÖ∩╕Å' },
  { key: 'COMPLETED', label: 'Completed', icon: 'Γ£à' },
  { key: 'OUT_FOR_DELIVERY', label: 'Out for Delivery', icon: '≡ƒÜÜ' },
  { key: 'DELIVERED', label: 'Delivered', icon: '≡ƒÄë' },
];

const marketplaceStatusSteps = [
  { key: 'NOT_STARTED', label: 'Order Placed', icon: 'ΓÅ│' },
  { key: 'OUT_FOR_DELIVERY', label: 'Out for Delivery', icon: '≡ƒÜÜ' },
  { key: 'DELIVERED', label: 'Delivered', icon: '≡ƒÄë' },
];

export default function CustomerOrdersPage() {
  const { socket } = useSocket();
  const [orders, setOrders] = useState<any[]>([]);
  const [refunds, setRefunds] = useState<Record<string, any>>({});
  const [hasMoreHistory, setHasMoreHistory] = useState(false);
  const [loading, setLoading] = useState(true);
  const [loadingHistory, setLoadingHistory] = useState(false);
  const [error, setError] = useState('');

  useEffect(() => {
    Promise.all([
      orderApi.customerOrders(),
      refundApi.customerRefunds().catch(() => []) // Fallback to empty if fails
    ]).then(([ordersData, refundsData]) => {
      setOrders((ordersData as any).orders || []);
      setHasMoreHistory((ordersData as any).hasMoreHistory || false);

      const refundMap: Record<string, any> = {};
      if (Array.isArray(refundsData)) {
        refundsData.forEach((r: any) => { refundMap[r.orderId] = r; });
      }
      setRefunds(refundMap);
    }).catch((err) => setError(err.message || 'Failed to load data'))
      .finally(() => setLoading(false));
  }, []);

  const loadRefunds = async () => {
    try {
      const refundsData = await refundApi.customerRefunds();
      const refundMap: Record<string, any> = {};
      if (Array.isArray(refundsData)) {
        refundsData.forEach((r: any) => { refundMap[r.orderId] = r; });
      }
      setRefunds(refundMap);
    } catch {
      // Background re-fetch failed silently
    }
  };

  useEffect(() => {
    if (!socket) return;

    // Listen for real-time status updates and adjust the matching order in state
    const handleStatusUpdate = (eventPayload: any) => {
      // payload usually contains { orderId, status, trackingEvent }
      setOrders((prev) => prev.map(o => {
        if (o.id === eventPayload.orderId) {
          const newTracking = eventPayload.trackingEvent 
            ? [eventPayload.trackingEvent, ...(o.trackingEvents || [])]
            : o.trackingEvents;
          return { ...o, status: eventPayload.status, trackingEvents: newTracking };
        }
        return o;
      }));
    };

    // Live update the refund panel when the vendor or admin changes its state
    const handleRefundUpdate = () => loadRefunds();

    socket.on('order:status_updated', handleStatusUpdate);
    socket.on('refund:vendor_response', handleRefundUpdate);
    socket.on('refund:replacement_shipped', handleRefundUpdate);
    socket.on('refund:resolved', handleRefundUpdate);

    return () => {
      socket.off('order:status_updated', handleStatusUpdate);
      socket.off('refund:vendor_response', handleRefundUpdate);
      socket.off('refund:replacement_shipped', handleRefundUpdate);
      socket.off('refund:resolved', handleRefundUpdate);
    };
  }, [socket]);

  const loadFullHistory = async () => {
    setLoadingHistory(true);
    try {
      const data: any = await orderApi.customerOrders(true);
      setOrders(data.orders || []);
      setHasMoreHistory(false);
    } catch (err: any) {
      setError(err.message || 'Failed to load history');
    } finally {
      setLoadingHistory(false);
    }
  };

  const handleHideOrder = async (orderId: string) => {
    if (!confirm('Hide this delivered order from your dashboard?')) return;
    try {
      await orderApi.hideOrder(orderId);
      setOrders(orders.filter(o => o.id !== orderId));
    } catch (err: any) {
      setError(err.message || 'Failed to hide order');
    }
  };

  const handleConfirmReceipt = async (orderId: string) => {
    try {
      await orderApi.confirmReceipt(orderId);
      setOrders(orders.map(o => o.id === orderId ? { ...o, status: 'DELIVERED', deliveredAt: new Date().toISOString() } : o));
    } catch (err: any) {
      setError(err.message || 'Failed to confirm receipt');
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="w-8 h-8 spinner" />
      </div>
    );
  }

  return (
    <div className="max-w-3xl mx-auto">
      <div className="mb-6">
        <h1 className="text-2xl font-bold text-white">My Orders</h1>
        <p className="text-slate-400 text-sm mt-1">Track the manufacturing status of your prints</p>
      </div>

      {error && (
        <div className="mb-4 px-4 py-3 rounded-lg bg-red-900/30 border border-red-900/50 text-red-400 text-sm">{error}</div>
      )}

      {orders.length === 0 ? (
        <div className="glass rounded-2xl p-12 text-center flex flex-col items-center">
          <div className="relative w-48 h-48 mb-6 opacity-80">
            <Image src="/dashboard/empty_orders.jfif" alt="No Orders" fill className="object-contain" />
          </div>
          <h3 className="text-xl font-semibold text-white mb-2">No orders yet</h3>
          <p className="text-slate-400 text-sm">Accept a vendor quote to create your first order.</p>
        </div>
      ) : (
        <div className="space-y-6">
          {orders.map((order: any) => {
            const isMarketplace = !(order.quoteId || order.quote);
            const activeStatusSteps = isMarketplace ? marketplaceStatusSteps : statusSteps;
            const currentStep = activeStatusSteps.findIndex(s => s.key === order.status);

            return (
              <div key={order.id} className="glass rounded-2xl p-6">
                <div className="flex items-start justify-between mb-4">
                  <div>
                    <p className="text-xs text-slate-500 mb-1">{isMarketplace ? 'Marketplace Order ID' : 'Order ID'}</p>
                    <h3 className="font-mono text-sm text-white font-bold">#{order.id.slice(-8).toUpperCase()}</h3>
                    <p className="text-sm text-slate-400 mt-1">
                      Vendor: <span className="text-white">{order.vendor?.user?.name || order.vendor?.companyName}</span>
                    </p>
                  </div>
                  <div className="text-right">
                    <p className="text-xs text-slate-500">Total</p>
                    <p className="text-xl font-bold text-violet-400">Γé╣{order.finalAmount}</p>
                    <p className="text-xs text-slate-500 mt-1">{new Date(order.createdAt).toLocaleDateString()}</p>
                  </div>
                </div>

                {/* Status Timeline */}
                <div className="mt-4 mb-2">
                  <div className="flex items-center justify-between relative">
                    {/* Progress line */}
                    <div className="absolute top-4 left-0 right-0 h-0.5 bg-white/10 z-0" />
                    <div
                      className="absolute top-4 left-0 h-0.5 bg-violet-600 z-0 transition-all duration-700"
                      style={{ width: `${(currentStep / (activeStatusSteps.length - 1)) * 100}%` }}
                    />

                    {activeStatusSteps.map((step, idx) => {
                      const done = idx <= currentStep;
                      const current = idx === currentStep;
                      return (
                        <div key={step.key} className="flex flex-col items-center z-10 relative" style={{ width: `${100 / activeStatusSteps.length}%` }}>
                          <div
                            className={`w-8 h-8 rounded-full flex items-center justify-center text-sm transition-all ${
                              current
                                ? 'bg-violet-600 ring-2 ring-violet-400 ring-offset-2 ring-offset-[#0a0a0f]'
                                : done
                                ? 'bg-violet-900'
                                : 'bg-white/5'
                            }`}
                          >
                            {step.icon}
                          </div>
                          <p className={`text-xs mt-2 text-center leading-tight ${done ? 'text-slate-300' : 'text-slate-600'}`}>
                            {step.label}
                          </p>
                        </div>
                      );
                    })}
                  </div>
                </div>

                {/* Shipping info */}
                {order.deliveryAddress && (
                  <div className="mt-6 mb-2 p-3 rounded-xl bg-white/[0.03] border border-white/5 flex gap-3">
                    <span className="text-sm mt-0.5 opacity-80">≡ƒôì</span>
                    <div>
                      <p className="text-xs text-slate-500 mb-0.5">Shipping Destination</p>
                      <p className="text-sm text-slate-300">
                        {order.deliveryAddress}
                        {(order.city || order.state || order.pincode) && (
                          <span className="block text-xs mt-1 text-slate-400">
                            {[order.city, order.state, order.pincode].filter(Boolean).join(', ')}
                          </span>
                        )}
                      </p>
                    </div>
                  </div>
                )}

                {/* Tracking log */}
                {order.trackingEvents?.length > 0 && (
                  <div className="mt-4 pt-4 border-t border-white/5">
                    <p className="text-xs text-slate-500 mb-2">History</p>
                    <div className="space-y-1">
                      {[...order.trackingEvents].reverse().slice(0, 3).map((ev: any) => (
                        <div key={ev.id} className="flex items-center gap-2 text-xs text-slate-400">
                           <span className="w-1.5 h-1.5 rounded-full bg-violet-500 flex-shrink-0" />
                          <span>{ev.note || ev.status}</span>
                          <span className="ml-auto text-slate-600">
                            {new Date(ev.updatedAt).toLocaleDateString()}
                          </span>
                        </div>
                      ))}
                    </div>
                  </div>
                )}

                {/* Refund Status & Info */}
                {refunds[order.id] && (
                  <div className="mt-4 p-3 rounded-xl bg-purple-900/10 border border-purple-500/20">
                    <p className="text-xs text-purple-400 font-semibold mb-1">
                      {refunds[order.id].type === 'FULL_RETURN' ? 'Return' : 'Refund'} Status: {refunds[order.id].status.replace('_', ' ')}
                    </p>

                    {refunds[order.id].status === 'REPLACEMENT_SHIPPED' && (
                      <div className="mt-2">
                        <p className="text-sm text-slate-300">
                          ≡ƒôª Replacement shipped! Tracking: <span className="text-white font-bold">{refunds[order.id].replacementTrackingId}</span>
                        </p>
                        <p className="text-xs text-slate-500 mt-1">Please confirm below once you receive it.</p>
                      </div>
                    )}
                  </div>
                )}

                <div className="mt-6 flex items-center justify-end gap-3 border-t border-white/5 pt-4">
                  {/* Replacement Confirmation Button */}
                  {refunds[order.id]?.status === 'REPLACEMENT_SHIPPED' ? (
                    <>
                      <p className="text-xs text-slate-400 mr-auto">Confirm replacement receipt to resolve case.</p>
                      <button
                        onClick={async () => {
                          try {
                            await refundApi.customerConfirm(refunds[order.id].id);
                            setRefunds((prev: Record<string, any>) => ({...prev, [order.id]: {...prev[order.id], status: 'RESOLVED_REPLACED'}}));
                          } catch (err: any) { alert(err.message); }
                        }}
                        className="px-4 py-2 bg-indigo-600 hover:bg-indigo-500 text-white rounded-lg text-sm font-medium transition-colors"
                      >
                        Γ£à Confirm Replacement Received
                      </button>
                    </>
                  ) : order.status !== 'DELIVERED' ? (
                    <>
                      <p className="text-xs text-slate-400 mr-auto">
                        {order.status === 'OUT_FOR_DELIVERY' ? 'Click when arrived safely.' : 'Waiting for vendor to ship out...'}
                      </p>
                      <button
                        onClick={() => handleConfirmReceipt(order.id)}
                        disabled={order.status !== 'OUT_FOR_DELIVERY'}
                        className={`px-4 py-2 rounded-lg text-sm font-medium transition-colors ${
                          order.status === 'OUT_FOR_DELIVERY'
                            ? 'bg-green-600 hover:bg-green-500 text-white'
                            : 'bg-green-900/40 border border-green-900/50 text-green-600 cursor-not-allowed opacity-50'
                        }`}
                      >
                        Γ£à Confirm Package Received
                      </button>
                    </>
                  ) : (
                    <>
                      <div className="px-4 py-2 bg-green-900/40 border border-green-800 text-green-400 rounded-lg text-sm font-medium inline-block mr-auto">
                        ≡ƒÄë Delivered
                      </div>

                      {/* 48h refund window */}
                      {(() => {
                        if (refunds[order.id]) return null; // Already filed

                        const hours = getRefundHoursLeft(order);
                        if (hours === null || hours <= 0) return null;

                        return (
                          <Link
                            href={`/dashboard/customer/refund/${order.id}`}
                            className="px-4 py-2 bg-amber-600/20 hover:bg-amber-600/40 border border-amber-500/40 text-amber-400 rounded-lg text-sm font-medium transition-colors flex items-center gap-1.5"
                          >
                            ≡ƒöä Refund
                            <span className="text-xs opacity-75">({Math.floor(hours)}h left)</span>
                          </Link>
                        );
                      })()}

                      <button
                        onClick={() => handleHideOrder(order.id)}
                        className="px-4 py-2 bg-slate-800 hover:bg-red-900/50 text-slate-300 hover:text-red-400 border border-slate-700 hover:border-red-900/50 rounded-lg text-sm font-medium transition-colors"
                      >
                        ≡ƒùæ∩╕Å Remove from History
                      </button>
                    </>
                  )}
                </div>

              </div>
            );
          })}
        </div>
      )}

      {hasMoreHistory && (
        <div className="mt-6 flex justify-center">
          <button
            onClick={loadFullHistory}
            disabled={loadingHistory}
            className="px-6 py-3 rounded-xl bg-white/5 hover:bg-white/10 border border-white/10 text-slate-300 font-medium transition-colors text-sm flex items-center gap-2"
          >
            {loadingHistory ? <div className="w-4 h-4 spinner" /> : '≡ƒôÜ Load Full Order History'}
          </button>
        </div>
      )}
    </div>
  );
}

'use client';

import { useState, useEffect, useRef } from 'react';
import { authApi } from '@/lib/api';
import { useAuth } from '@/context/AuthContext';
import { usePincode } from '@/hooks/usePincode';
import { 
  Loader2, 
  CheckCircle2, 
  User, 
  MapPin, 
  Mail, 
  ShieldCheck, 
  Camera, 
  Trash2, 
  Save,
  Globe,
  Navigation,
  X
} from 'lucide-react';
import Image from 'next/image';
import { motion } from 'framer-motion';

export default function CustomerProfilePage() {
  const { user } = useAuth();
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [form, setForm] = useState({ city: '', state: '', pincode: '', deliveryAddress: '' });
  const [avatarUrl, setAvatarUrl] = useState('');
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [uploading, setUploading] = useState(false);
  const [success, setSuccess] = useState('');
  const [error, setError] = useState('');
  const pincodeData = usePincode(form.pincode);

  useEffect(() => {
    if (pincodeData.isValid) {
      setForm(prev => ({
        ...prev,
        city: pincodeData.city || prev.city,
        state: pincodeData.state || prev.state
      }));
    }
  }, [pincodeData.isValid, pincodeData.city, pincodeData.state]);

  useEffect(() => {
    authApi.me().then((data: any) => {
      setForm({ city: data.city || '', state: data.state || '', pincode: data.pincode || '', deliveryAddress: data.deliveryAddress || '' });
      setAvatarUrl(data.avatarUrl || '');
    }).catch(() => {}).finally(() => setLoading(false));
  }, []);

  const handleAvatarChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setUploading(true);
    setError('');
    const fd = new FormData();
    fd.append('avatar', file);
    try {
      const res = await authApi.uploadAvatar(fd);
      setAvatarUrl(res.avatarUrl);
      setSuccess('Profile photo updated!');
      setTimeout(() => setSuccess(''), 3000);
    } catch (err: any) {
      setError(err.message || 'Upload failed');
    } finally {
      setUploading(false);
    }
  };

  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!form.pincode.trim()) { setError('PIN code is required.'); return; }
    if (!/^\d{6}$/.test(form.pincode.trim())) { setError('PIN code must be exactly 6 digits.'); return; }
    if (!pincodeData.isValid && form.pincode.length === 6) { setError('Please enter a valid Indian PIN code.'); return; }

    setSaving(true);
    setError('');
    setSuccess('');

    try {
      await authApi.updateProfile(form);
      setSuccess('Profile saved successfully!');
      setTimeout(() => setSuccess(''), 5000);
    } catch (err: any) {
      setError(err.message || 'Failed to save profile');
    } finally {
      setSaving(false);
    }
  };

  const initials = user?.name?.split(' ').map(n => n[0]).join('').slice(0, 2).toUpperCase() || '?';

  if (loading) return (
    <div className="flex h-[60vh] items-center justify-center">
      <div className="flex flex-col items-center gap-4">
        <Loader2 className="w-10 h-10 text-violet-500 animate-spin" />
        <p className="text-slate-400 font-medium animate-pulse">Loading profile...</p>
      </div>
    </div>
  );

  return (
    <motion.div 
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      className="max-w-4xl mx-auto pb-12"
    >
      <div className="mb-8 flex items-end justify-between">
        <div>
          <h1 className="text-3xl font-black text-white tracking-tight">Profile Settings</h1>
          <p className="text-slate-400 mt-2 flex items-center gap-2">
            <ShieldCheck className="w-4 h-4 text-emerald-400" />
            Manage your personal identity and delivery preferences.
          </p>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Left Column: Photo & Account Quick Info */}
        <div className="lg:col-span-1 space-y-6">
          {/* Profile Photo */}
          <div className="glass rounded-3xl p-8 flex flex-col items-center text-center relative overflow-hidden group">
            <div className="absolute inset-0 bg-gradient-to-b from-violet-600/10 to-transparent opacity-0 group-hover:opacity-100 transition-opacity" />

            <div className="relative mb-6">
              <div className="w-32 h-32 rounded-full overflow-hidden border-4 border-white/10 bg-gradient-to-br from-violet-600 to-indigo-600 flex items-center justify-center shadow-2xl relative group/avatar">
                {avatarUrl ? (
                  <Image src={avatarUrl} alt="Profile" fill className="object-cover transition-transform group-hover/avatar:scale-110 duration-500" />
                ) : (
                  <span className="text-4xl font-black text-white">{initials}</span>
                )}

                <button
                  onClick={() => fileInputRef.current?.click()}
                  className="absolute inset-0 bg-black/60 opacity-0 group-hover/avatar:opacity-100 flex flex-col items-center justify-center transition-all duration-300"
                >
                  <Camera className="w-8 h-8 text-white mb-1" />
                  <span className="text-[10px] font-bold text-white uppercase tracking-widest">Change</span>
                </button>
              </div>

              {uploading && (
                <div className="absolute inset-0 rounded-full bg-black/40 backdrop-blur-sm flex items-center justify-center">
                  <Loader2 className="w-8 h-8 text-white animate-spin" />
                </div>
              )}
            </div>

            <h3 className="text-xl font-bold text-white mb-1">{user?.name}</h3>
            <p className="text-slate-500 text-sm flex items-center gap-1 justify-center">
              <Mail className="w-3 h-3" /> {user?.email}
            </p>

            <div className="mt-6 w-full pt-6 border-t border-white/5 flex flex-col gap-2">
              <input ref={fileInputRef} type="file" accept="image/*" className="hidden" onChange={handleAvatarChange} />
              <button
                onClick={() => fileInputRef.current?.click()}
                disabled={uploading}
                className="w-full py-3 rounded-2xl bg-white/5 hover:bg-white/10 border border-white/10 text-white text-xs font-black uppercase tracking-widest transition-all disabled:opacity-50 active:scale-95"
              >
                Upload New Photo
              </button>
              {avatarUrl && (
                <button
                  onClick={() => { setAvatarUrl(''); authApi.updateProfile({ avatarUrl: '' }); }}
                  className="w-full py-3 rounded-2xl bg-red-500/5 hover:bg-red-500/10 text-red-400 text-[10px] font-black uppercase tracking-widest transition-all active:scale-95 flex items-center justify-center gap-2"
                >
                  <Trash2 className="w-3 h-3" /> Remove Photo
                </button>
              )}
            </div>
          </div>

          {/* Role Badge */}
          <div className="glass rounded-3xl p-6 border-l-4 border-violet-500">
            <div className="flex items-center gap-4">
              <div className="w-12 h-12 rounded-2xl bg-violet-600/20 flex items-center justify-center">
                <ShieldCheck className="w-6 h-6 text-violet-400" />
              </div>
              <div>
                <p className="text-[10px] font-bold text-violet-400 uppercase tracking-widest">Account Type</p>
                <p className="text-lg font-black text-white uppercase">{user?.role}</p>
              </div>
            </div>
          </div>
        </div>

        {/* Right Column: Detailed Info Form */}
        <div className="lg:col-span-2 space-y-8">
          <form onSubmit={handleSave} className="space-y-8">
            {/* Account Information Section */}
            <section className="glass rounded-3xl p-8 relative overflow-hidden">
              <div className="absolute top-0 right-0 p-8 opacity-5">
                <User className="w-24 h-24 text-white" />
              </div>

              <h3 className="text-sm font-black text-violet-400 uppercase tracking-[0.2em] mb-8 flex items-center gap-2">
                <div className="w-6 h-1 bg-violet-500 rounded-full" />
                Account Information
              </h3>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-xs font-bold text-slate-400 uppercase tracking-wider ml-1">Full Name</label>
                  <div className="relative group">
                    <User className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500 group-focus-within:text-violet-400 transition-colors" />
                    <input 
                      value={user?.name} 
                      disabled 
                      className="w-full pl-12 pr-4 py-4 rounded-2xl bg-white/5 border border-white/5 text-slate-500 text-sm focus:outline-none cursor-not-allowed opacity-60" 
                    />
                  </div>
                </div>
                <div className="space-y-2">
                  <label className="text-xs font-bold text-slate-400 uppercase tracking-wider ml-1">Email Address</label>
                  <div className="relative group">
                    <Mail className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500 group-focus-within:text-violet-400 transition-colors" />
                    <input 
                      value={user?.email} 
                      disabled 
                      className="w-full pl-12 pr-4 py-4 rounded-2xl bg-white/5 border border-white/5 text-slate-500 text-sm focus:outline-none cursor-not-allowed opacity-60" 
                    />
                  </div>
                </div>
              </div>
            </section>

            {/* Delivery Details Section */}
            <section className="glass rounded-3xl p-8 relative overflow-hidden">
              <div className="absolute top-0 right-0 p-8 opacity-5">
                <Navigation className="w-24 h-24 text-white" />
              </div>

              <h3 className="text-sm font-black text-violet-400 uppercase tracking-[0.2em] mb-8 flex items-center gap-2">
                <div className="w-6 h-1 bg-violet-500 rounded-full" />
                Delivery Logistics
              </h3>

              <div className="space-y-6">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  {/* PIN Code */}
                  <div className="space-y-2">
                    <label className="text-xs font-bold text-slate-400 uppercase tracking-wider ml-1 flex justify-between">
                      PIN Code <span className="text-red-500/50">* Required</span>
                    </label>
                    <div className="relative">
                      <MapPin className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500" />
                      <input
                        value={form.pincode}
                        onChange={e => {
                          const pin = e.target.value.replace(/\D/g, '').slice(0, 6);
                          setForm(f => ({ ...f, pincode: pin }));
                        }}
                        placeholder="6-digit PIN" maxLength={6} inputMode="numeric" required
                        className={`w-full pl-12 pr-12 py-4 rounded-2xl bg-white/5 border text-white placeholder-slate-600 focus:outline-none text-sm transition-all ${
                          pincodeData.isValid ? 'border-emerald-500/50 bg-emerald-500/5' : pincodeData.error ? 'border-red-500/50 bg-red-500/5' : 'border-white/10 focus:border-violet-500 focus:bg-white/10'
                        }`}
                      />
                      <div className="absolute right-4 top-1/2 -translate-y-1/2">
                        {pincodeData.loading && <Loader2 className="w-5 h-5 text-violet-400 animate-spin" />}
                        {!pincodeData.loading && pincodeData.isValid && <CheckCircle2 className="w-5 h-5 text-emerald-500 animate-in zoom-in duration-300" />}
                      </div>
                    </div>
                    {pincodeData.error && <p className="text-[10px] font-bold text-red-400 uppercase tracking-wider mt-1 px-1">ΓÜá∩╕Å {pincodeData.error}</p>}
                  </div>

                  {/* City */}
                  <div className="space-y-2">
                    <label className="text-xs font-bold text-slate-400 uppercase tracking-wider ml-1">City / District</label>
                    <div className="relative group">
                      <Globe className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500 group-focus-within:text-violet-400 transition-colors" />
                      <input 
                        value={form.city} 
                        onChange={e => setForm({ ...form, city: e.target.value })}
                        readOnly={pincodeData.isValid}
                        placeholder="e.g. Mumbai"
                        className="w-full pl-12 pr-4 py-4 rounded-2xl bg-white/5 border border-white/10 text-white placeholder-slate-600 focus:outline-none focus:border-violet-500 focus:bg-white/10 text-sm transition-all read-only:opacity-60" 
                      />
                    </div>
                  </div>
                </div>

                {/* State */}
                <div className="space-y-2">
                  <label className="text-xs font-bold text-slate-400 uppercase tracking-wider ml-1">State</label>
                  <div className="relative group">
                    <div className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500 group-focus-within:text-violet-400 transition-colors flex items-center justify-center text-[10px] font-black border border-slate-700 rounded">IN</div>
                    <input 
                      value={form.state} 
                      onChange={e => setForm({ ...form, state: e.target.value })}
                      readOnly={pincodeData.isValid}
                      placeholder="e.g. Maharashtra"
                      className="w-full pl-12 pr-4 py-4 rounded-2xl bg-white/5 border border-white/10 text-white placeholder-slate-600 focus:outline-none focus:border-violet-500 focus:bg-white/10 text-sm transition-all read-only:opacity-60" 
                    />
                  </div>
                </div>

                {/* Address */}
                <div className="space-y-2">
                  <label className="text-xs font-bold text-slate-400 uppercase tracking-wider ml-1">Full Delivery Address</label>
                  <textarea 
                    value={form.deliveryAddress} 
                    onChange={e => setForm({ ...form, deliveryAddress: e.target.value })}
                    placeholder="Flat/House No., Building, Street, Area, Landmarks..."
                    rows={4} 
                    className="w-full px-5 py-4 rounded-3xl bg-white/5 border border-white/10 text-white placeholder-slate-600 focus:outline-none focus:border-violet-500 focus:bg-white/10 text-sm resize-none transition-all" 
                  />
                </div>
              </div>
            </section>

            {/* Notification/Message Area */}
            {(error || success) && (
              <motion.div 
                initial={{ opacity: 0, scale: 0.95 }}
                animate={{ opacity: 1, scale: 1 }}
                className={`p-4 rounded-2xl border flex items-center gap-3 ${
                  error ? 'bg-red-500/10 border-red-500/20 text-red-400' : 'bg-emerald-500/10 border-emerald-500/20 text-emerald-400'
                }`}
              >
                {error ? <X className="w-5 h-5 flex-shrink-0" /> : <CheckCircle2 className="w-5 h-5 flex-shrink-0" />}
                <p className="text-sm font-bold tracking-wide">{error || success}</p>
              </motion.div>
            )}

            {/* Submit Button */}
            <div className="flex justify-end">
              <button 
                type="submit" 
                disabled={saving}
                className="group relative px-10 py-5 rounded-2xl bg-gradient-to-br from-violet-600 to-indigo-600 text-white font-black uppercase tracking-widest text-xs shadow-xl shadow-violet-900/40 hover:scale-105 active:scale-95 transition-all disabled:opacity-50 disabled:hover:scale-100 flex items-center gap-3 overflow-hidden"
              >
                <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/20 to-transparent -translate-x-full group-hover:translate-x-full transition-transform duration-1000" />
                {saving ? (
                  <>
                    <Loader2 className="w-4 h-4 animate-spin" />
                    <span>Processing...</span>
                  </>
                ) : (
                  <>
                    <Save className="w-4 h-4 group-hover:rotate-12 transition-transform" />
                    <span>Save Changes</span>
                  </>
                )}
              </button>
            </div>
          </form>
        </div>
      </div>
    </motion.div>
  );
}

'use client';

import { useState, useEffect } from 'react';
import { quoteApi, orderApi } from '@/lib/api';
import { useSocket } from '@/context/SocketContext';
import Image from 'next/image';

const statusColors: Record<string, string> = {
  PENDING: 'bg-yellow-900/50 text-yellow-400',
  ACCEPTED: 'bg-green-900/50 text-green-400',
  REJECTED: 'bg-red-900/50 text-red-400',
};

export default function CustomerQuotesPage() {
  const { socket } = useSocket();
  const [quotes, setQuotes] = useState<any[]>([]);
  const [hasMoreHistory, setHasMoreHistory] = useState(false);
  const [loadingHistory, setLoadingHistory] = useState(false);
  const [loading, setLoading] = useState(true);
  const [orderSuccess, setOrderSuccess] = useState<string | null>(null);
  const [error, setError] = useState('');
  const [actionId, setActionId] = useState<string | null>(null);

  useEffect(() => {
    quoteApi.customerQuotes()
      .then((data: any) => {
        setQuotes(data.quotes || []);
        setHasMoreHistory(data.hasMoreHistory || false);
      })
      .catch(() => setError('Failed to load quotes'))
      .finally(() => setLoading(false));
  }, []);

  useEffect(() => {
    if (!socket) return;

    const handleQuoteReceived = (newQuote: any) => {
      setQuotes((prev) => [newQuote, ...prev]);
    };

    socket.on('quote:received', handleQuoteReceived);

    return () => {
      socket.off('quote:received', handleQuoteReceived);
    };
  }, [socket]);

  const loadFullHistory = async () => {
    setLoadingHistory(true);
    try {
      const data: any = await quoteApi.customerQuotes(true);
      setQuotes(data.quotes || []);
      setHasMoreHistory(false);
    } catch (err: any) {
      setError(err.message || 'Failed to load history');
    } finally {
      setLoadingHistory(false);
    }
  };

  const handleHideQuote = async (quoteId: string) => {
    if (!confirm('Remove this quote from your history?')) return;
    try {
      await quoteApi.hideQuote(quoteId);
      setQuotes(quotes.filter(q => q.id !== quoteId));
    } catch (err: any) {
      setError(err.message || 'Failed to hide quote');
    }
  };

  const handleAccept = async (quoteId: string) => {
    setActionId(quoteId + '_accept');
    setError('');
    try {
      const order: any = await orderApi.create({ quoteId });
      setOrderSuccess(`Order #${order.id.slice(-6).toUpperCase()} created! Track it in My Orders.`);
      setQuotes((prev) => prev.map((q) => q.id === quoteId ? { ...q, status: 'ACCEPTED' } : q));
    } catch (err: any) {
      setError(err.message);
    } finally {
      setActionId(null);
    }
  };

  const handleReject = async (quoteId: string) => {
    setActionId(quoteId + '_reject');
    setError('');
    try {
      await quoteApi.reject(quoteId);
      setQuotes((prev) => prev.map((q) => q.id === quoteId ? { ...q, status: 'REJECTED' } : q));
    } catch (err: any) {
      setError(err.message);
    } finally {
      setActionId(null);
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="w-8 h-8 spinner" />
      </div>
    );
  }

  return (
    <div className="max-w-3xl mx-auto">
      <div className="mb-6">
        <h1 className="text-2xl font-bold text-white">My Quotes</h1>
        <p className="text-slate-400 text-sm mt-1">Quotes received from vendors for your designs</p>
      </div>

      {error && (
        <div className="mb-4 px-4 py-3 rounded-lg bg-red-900/30 border border-red-900/50 text-red-400 text-sm">{error}</div>
      )}
      {orderSuccess && (
        <div className="mb-4 px-4 py-3 rounded-lg bg-green-900/30 border border-green-900/50 text-green-400 text-sm">{orderSuccess}</div>
      )}

      {quotes.length === 0 ? (
        <div className="glass rounded-2xl p-12 text-center flex flex-col items-center">
          <div className="relative w-48 h-48 mb-6 opacity-80">
            <Image src="/dashboard/empty_quotes.jfif" alt="No Quotes" fill className="object-contain" />
          </div>
          <h3 className="text-xl font-semibold text-white mb-2">No quotes yet</h3>
          <p className="text-slate-400 text-sm">Upload a design and send quote requests to vendors to see them here.</p>
        </div>
      ) : (
        <div className="space-y-4">
          {quotes.map((quote: any) => (
            <div key={quote.id} className="glass rounded-2xl p-5">
              <div className="flex items-start justify-between mb-4">
                <div>
                  <h3 className="font-semibold text-white">
                    {quote.vendor?.user?.name || quote.vendor?.companyName || 'Vendor'}
                  </h3>
                  <p className="text-sm text-slate-400 mt-0.5">
                    Design: {quote.request?.design?.fileName || 'ΓÇö'}
                  </p>
                  {quote.request?.material && (
                    <p className="text-xs text-slate-500 mt-0.5">
                      {quote.request.material} ┬╖ {quote.request.infillDensity}% infill
                    </p>
                  )}
                </div>
                <span className={`status-pill ${statusColors[quote.status] || 'bg-gray-800 text-gray-400'}`}>
                  {quote.status}
                </span>
              </div>

              {/* Price Breakdown */}
              <div className="bg-white/[0.03] rounded-xl p-4 mb-4 space-y-1.5 text-sm">
                {[
                  { label: 'Material Cost', value: quote.materialCost },
                  { label: 'Machine Cost', value: quote.machineCost },
                  { label: 'Labor Cost', value: quote.laborCost },
                  { label: 'GST (18%)', value: quote.gst },
                  { label: 'Platform Fee (10%)', value: quote.platformFee },
                ].map(({ label, value }) => (
                  <div key={label} className="flex justify-between text-slate-400">
                    <span>{label}</span>
                    <span>Γé╣{Number(value).toFixed(2)}</span>
                  </div>
                ))}
                <div className="flex justify-between text-white font-bold pt-2 border-t border-white/10">
                  <span>Total</span>
                  <span className="text-violet-400 text-lg">Γé╣{Number(quote.totalCost || quote.totalPrice).toFixed(2)}</span>
                </div>
              </div>

              {quote.notes && (
                <p className="text-sm text-slate-400 mb-4 italic">"{quote.notes}"</p>
              )}

              {quote.status === 'PENDING' && (
                <div className="flex gap-3">
                  <button
                    onClick={() => handleAccept(quote.id)}
                    disabled={actionId !== null}
                    className="flex-1 py-2.5 rounded-xl bg-violet-600 hover:bg-violet-500 disabled:opacity-50 text-white font-medium text-sm transition-colors"
                  >
                    {actionId === quote.id + '_accept' ? 'Creating order...' : 'Γ£à Accept & Order'}
                  </button>
                  <button
                    onClick={() => handleReject(quote.id)}
                    disabled={actionId !== null}
                    className="px-5 py-2.5 rounded-xl bg-white/5 hover:bg-red-900/30 border border-white/10 hover:border-red-900/50 text-slate-400 hover:text-red-400 font-medium text-sm transition-all disabled:opacity-50"
                  >
                    {actionId === quote.id + '_reject' ? '...' : 'Reject'}
                  </button>
                </div>
              )}

              {['ACCEPTED', 'REJECTED'].includes(quote.status) && (
                <div className="mt-4 pt-4 border-t border-white/10">
                  <button
                    onClick={() => handleHideQuote(quote.id)}
                    className="w-full py-2 bg-slate-800 hover:bg-red-900/50 text-slate-400 hover:text-red-400 border border-slate-700 hover:border-red-900/50 rounded-xl text-sm font-medium transition-colors"
                  >
                    ≡ƒùæ∩╕Å Remove from History
                  </button>
                </div>
              )}
            </div>
          ))}
        </div>
      )}

      {hasMoreHistory && (
        <div className="mt-8 flex justify-center">
          <button
            onClick={loadFullHistory}
            disabled={loadingHistory}
            className="px-6 py-3 rounded-xl bg-white/5 hover:bg-white/10 border border-white/10 text-slate-300 font-medium transition-colors text-sm flex items-center gap-2"
          >
            {loadingHistory ? <div className="w-4 h-4 spinner" /> : '≡ƒôÜ Load Full Quote History'}
          </button>
        </div>
      )}
    </div>
  );
}

'use client';

import { useState, useEffect } from 'react';
import { useParams, useRouter } from 'next/navigation';
import { orderApi, refundApi } from '@/lib/api';

const REFUND_TYPES = [
  {
    key: 'WRONG_ORDER',
    label: '≡ƒôª Wrong Order',
    desc: 'I received a different item than what I ordered.',
    resolution: 'Vendor will ship the correct item.',
    color: 'from-blue-600/20 to-blue-800/10 border-blue-500/30',
  },
  {
    key: 'PARTIAL_DAMAGE',
    label: '≡ƒöº Partially Damaged',
    desc: 'Part of the model is broken or has print defects.',
    resolution: 'Vendor will repair or reprint the item.',
    color: 'from-yellow-600/20 to-yellow-800/10 border-yellow-500/30',
  },
  {
    key: 'FULL_DAMAGE',
    label: '≡ƒÆö Fully Damaged',
    desc: 'The entire model arrived broken or unusable.',
    resolution: 'Vendor will reprint and send a new item.',
    color: 'from-red-600/20 to-red-800/10 border-red-500/30',
  },
  {
    key: 'FULL_RETURN',
    label: 'Γå⌐∩╕Å Full Return',
    desc: 'I want to return the item and get a refund.',
    resolution: 'You send the item back. Receive 85% of the order amount. (5% platform handling + 10% vendor return fee deducted.)',
    color: 'from-purple-600/20 to-purple-800/10 border-purple-500/30',
  },
];

export default function RefundRequestPage() {
  const params = useParams();
  const router = useRouter();
  const orderId = params?.orderId as string;

  const [order, setOrder] = useState<any>(null);
  const [loading, setLoading] = useState(true);
  const [selectedType, setSelectedType] = useState('');
  const [description, setDescription] = useState('');
  const [photoFile, setPhotoFile] = useState<File | null>(null);
  const [videoFile, setVideoFile] = useState<File | null>(null);
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState('');
  const [step, setStep] = useState<'select' | 'details' | 'upload' | 'done'>('select');
  const [refundId, setRefundId] = useState('');

  useEffect(() => {
    orderApi.getStatus(orderId)
      .then((data: any) => setOrder(data))
      .catch(() => setError('Could not load order details.'))
      .finally(() => setLoading(false));
  }, [orderId]);

  const hoursRemaining = () => {
    if (!order?.deliveredAt) return null;
    const delivered = new Date(order.deliveredAt);
    const deadline = new Date(delivered.getTime() + 48 * 60 * 60 * 1000);
    const remaining = (deadline.getTime() - Date.now()) / (1000 * 60 * 60);
    return Math.max(0, remaining);
  };

  const timeLeft = hoursRemaining();
  const windowExpired = timeLeft !== null && timeLeft <= 0;

  const handleSubmitRequest = async () => {
    if (!selectedType || !description.trim()) {
      setError('Please select a refund type and provide a description.');
      return;
    }
    setSubmitting(true);
    setError('');
    try {
      const result: any = await refundApi.request({ orderId, type: selectedType, description });
      setRefundId(result.id);
      setStep('upload');
    } catch (err: any) {
      setError(err.message || 'Failed to submit refund request.');
    } finally {
      setSubmitting(false);
    }
  };

  const handleUploadProof = async () => {
    if (!photoFile && !videoFile) {
      setStep('done'); // Allow skipping upload if no files
      return;
    }
    setSubmitting(true);
    setError('');
    try {
      const formData = new FormData();
      if (photoFile) formData.append('photo', photoFile);
      if (videoFile) formData.append('video', videoFile);
      await refundApi.uploadProof(refundId, formData);
      setStep('done');
    } catch (err: any) {
      setError(err.message || 'Failed to upload proof. Your request was filed, but evidence failed.');
    } finally {
      setSubmitting(false);
    }
  };

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="w-8 h-8 spinner" />
      </div>
    );
  }

  if (windowExpired) {
    return (
      <div className="max-w-lg mx-auto py-16 px-4 text-center">
        <div className="glass rounded-2xl p-10">
          <div className="text-5xl mb-4">ΓÅ░</div>
          <h1 className="text-2xl font-bold text-white mb-3">Refund Window Closed</h1>
          <p className="text-slate-400">The 48-hour refund window for this order has expired. Refunds can only be requested within 48 hours of confirming delivery.</p>
          <button onClick={() => router.push('/dashboard/customer/orders')} className="mt-6 px-6 py-2.5 rounded-xl bg-violet-600 hover:bg-violet-500 text-white font-medium transition-colors">
            Back to Orders
          </button>
        </div>
      </div>
    );
  }

  if (step === 'done') {
    return (
      <div className="max-w-lg mx-auto py-16 px-4 text-center">
        <div className="glass rounded-2xl p-10">
          <div className="text-5xl mb-4">Γ£à</div>
          <h1 className="text-2xl font-bold text-white mb-3">Refund Request Filed!</h1>
          <p className="text-slate-400 mb-2">Your request has been sent to the vendor. They have <strong className="text-white">72 hours</strong> to respond.</p>
          <p className="text-slate-500 text-sm">Payment is frozen and will not be released to the vendor until this is resolved.</p>
          <button onClick={() => router.push('/dashboard/customer/orders')} className="mt-6 px-6 py-2.5 rounded-xl bg-violet-600 hover:bg-violet-500 text-white font-medium transition-colors">
            Back to Orders
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-2xl mx-auto py-8 px-4 space-y-6">
      {/* Header */}
      <div>
        <button onClick={() => router.back()} className="text-slate-500 hover:text-slate-300 text-sm mb-4 flex items-center gap-1">
          ΓåÉ Back
        </button>
        <h1 className="text-2xl font-bold text-white">Request a Refund</h1>
        {timeLeft !== null && (
          <p className="text-sm text-amber-400 mt-1">
            ΓÅ│ Refund window closes in <strong>{Math.floor(timeLeft)}h {Math.round((timeLeft % 1) * 60)}m</strong>
          </p>
        )}
        {order && (
          <p className="text-slate-500 text-sm mt-1">Order #{orderId.slice(-8)} ┬╖ Γé╣{order.finalAmount}</p>
        )}
      </div>

      {error && (
        <div className="p-3 rounded-xl bg-red-500/10 border border-red-500/30 text-red-400 text-sm">{error}</div>
      )}

      {/* Step 1: Select refund type */}
      {(step === 'select' || step === 'details') && (
        <div className="space-y-3">
          <h2 className="text-sm font-semibold text-slate-400 uppercase tracking-wider">What is the issue?</h2>
          {REFUND_TYPES.map(type => (
            <button
              key={type.key}
              onClick={() => { setSelectedType(type.key); setStep('details'); }}
              className={`w-full text-left p-4 rounded-xl bg-gradient-to-br border transition-all ${type.color} ${selectedType === type.key ? 'ring-2 ring-violet-500' : 'hover:border-white/20'}`}
            >
              <p className="text-white font-semibold text-sm">{type.label}</p>
              <p className="text-slate-400 text-xs mt-1">{type.desc}</p>
              <p className="text-violet-400 text-xs mt-1.5 font-medium">Resolution: {type.resolution}</p>
            </button>
          ))}
        </div>
      )}

      {/* Step 2: Description */}
      {step === 'details' && selectedType && (
        <div className="glass rounded-xl p-5 space-y-4">
          <h2 className="text-sm font-semibold text-slate-400 uppercase tracking-wider">Describe the issue</h2>
          <textarea
            value={description}
            onChange={e => setDescription(e.target.value)}
            rows={4}
            placeholder="Please describe the problem in detail. What did you receive? What was wrong with it?"
            className="w-full px-4 py-3 rounded-xl bg-white/5 border border-white/10 text-white placeholder-slate-600 focus:outline-none focus:border-violet-500 text-sm resize-none"
          />
          <p className="text-slate-500 text-xs">≡ƒÆí You'll be able to upload photo and video evidence in the next step.</p>
          <button
            onClick={handleSubmitRequest}
            disabled={submitting || !description.trim()}
            className="w-full py-3 rounded-xl bg-violet-600 hover:bg-violet-500 disabled:opacity-50 text-white font-semibold transition-colors"
          >
            {submitting ? 'Filing Request...' : 'File Refund Request ΓåÆ'}
          </button>
        </div>
      )}

      {/* Step 3: Upload proof */}
      {step === 'upload' && (
        <div className="glass rounded-xl p-5 space-y-5">
          <div>
            <h2 className="text-white font-semibold mb-1">Upload Proof (Recommended)</h2>
            <p className="text-slate-400 text-xs">Strong proof significantly improves your chances of a successful refund. Upload a photo AND an unboxing video if possible.</p>
          </div>

          {/* Photo upload */}
          <div>
            <label className="text-xs text-slate-400 mb-2 block font-semibold">≡ƒô╖ Damage Photo</label>
            <input
              type="file"
              accept="image/*"
              onChange={e => setPhotoFile(e.target.files?.[0] || null)}
              className="w-full text-sm text-slate-400 file:mr-3 file:py-2 file:px-4 file:rounded-lg file:border-0 file:text-sm file:bg-white/10 file:text-white hover:file:bg-white/20"
            />
            {photoFile && <p className="text-xs text-green-400 mt-1">Γ£ô {photoFile.name}</p>}
          </div>

          {/* Video upload */}
          <div>
            <label className="text-xs text-slate-400 mb-2 block font-semibold">≡ƒÄÑ Unboxing Video <span className="text-violet-400">(Strongest proof)</span></label>
            <p className="text-[11px] text-slate-600 mb-2">Record yourself opening the package for the first time. This proves the damage existed at delivery. Max 200MB.</p>
            <input
              type="file"
              accept="video/*"
              onChange={e => setVideoFile(e.target.files?.[0] || null)}
              className="w-full text-sm text-slate-400 file:mr-3 file:py-2 file:px-4 file:rounded-lg file:border-0 file:text-sm file:bg-white/10 file:text-white hover:file:bg-white/20"
            />
            {videoFile && <p className="text-xs text-green-400 mt-1">Γ£ô {videoFile.name} ({(videoFile.size / (1024 * 1024)).toFixed(1)}MB)</p>}
          </div>

          <div className="flex gap-3">
            <button
              onClick={() => setStep('done')}
              className="flex-1 py-2.5 rounded-xl bg-white/5 hover:bg-white/10 border border-white/10 text-slate-400 text-sm transition-colors"
            >
              Skip ΓÇö File Without Proof
            </button>
            <button
              onClick={handleUploadProof}
              disabled={submitting || (!photoFile && !videoFile)}
              className="flex-1 py-2.5 rounded-xl bg-violet-600 hover:bg-violet-500 disabled:opacity-50 text-white font-semibold text-sm transition-colors"
            >
              {submitting ? 'Uploading...' : 'Submit with Proof'}
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

'use client';

import { useState, useCallback, useEffect } from 'react';
import dynamic from 'next/dynamic';
import { designApi, quoteApi, authApi } from '@/lib/api';
import Image from 'next/image';

const ThreeViewer = dynamic(() => import('@/components/ThreeViewer'), {
  ssr: false,
  loading: () => (
    <div className="h-64 bg-black/30 rounded-xl flex items-center justify-center">
      <div className="w-6 h-6 spinner" />
    </div>
  ),
});

const API_BASE = process.env.NEXT_PUBLIC_API_URL || 'http://localhost:5000';

export default function UploadDesignPage() {
  const [files, setFiles] = useState<any[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [dragging, setDragging] = useState(false);
  const [previewFile, setPreviewFile] = useState<any>(null);
  const [vendors, setVendors] = useState<any[]>([]);
  const [uploadedFile, setUploadedFile] = useState<any>(null);
  const [quoteForm, setQuoteForm] = useState({
    vendorId: '',
    material: 'PLA',
    infillDensity: 20,
    notes: '',
    deliveryAddress: '',
    city: '',
    state: '',
    pincode: '',
  });
  const [quoteLoading, setQuoteLoading] = useState(false);
  const [quoteSuccess, setQuoteSuccess] = useState('');
  const [vendorSearch, setVendorSearch] = useState('');
  const [customerCity, setCustomerCity] = useState('');
  const [savingCity, setSavingCity] = useState(false);
  const [cityEditing, setCityEditing] = useState(false);

  useEffect(() => {
    // Load user profile to get saved city + delivery address
    authApi.me().then((user: any) => {
      if (user?.city) setCustomerCity(user.city);
      else setCityEditing(true);
      setQuoteForm(prev => ({
        ...prev,
        deliveryAddress: user?.deliveryAddress || '',
        city: user?.city || '',
        state: user?.state || '',
        pincode: user?.pincode || '',
      }));
    }).catch(() => {});

    designApi.myFiles().then((f: any) => setFiles(f)).catch(() => {});
  }, []);

  useEffect(() => {
    const cityParam = customerCity ? `?city=${encodeURIComponent(customerCity)}` : '';
    fetch(`${API_BASE}/vendors${cityParam}`)
      .then(r => r.json())
      .then(v => {
        if (Array.isArray(v)) setVendors(v);
        else {
          console.error('Vendors API error:', v);
          setVendors([]);
        }
      })
      .catch(err => { console.error('Vendors fetch failed:', err); setVendors([]); });
  }, [customerCity]);

  const handleSaveCity = async () => {
    if (!customerCity.trim()) return;
    setSavingCity(true);
    try {
      await authApi.updateProfile({ city: customerCity.trim() });
      setCityEditing(false);
      // Reload vendors with city
      const v = await fetch(`${API_BASE}/vendors?city=${encodeURIComponent(customerCity)}`).then(r => r.json());
      setVendors(Array.isArray(v) ? v : []);
    } catch {}
    finally { setSavingCity(false); }
  };

  const handleDrop = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setDragging(false);
    const file = e.dataTransfer.files[0];
    if (file) handleUpload(file);
  }, []);

  const handleUpload = async (file: File) => {
    if (!file.name.match(/\.(stl|obj)$/i)) {
      setError('Only .stl and .obj files are supported');
      return;
    }
    setError('');
    setLoading(true);
    const formData = new FormData();
    formData.append('file', file);
    try {
      const result: any = await designApi.upload(formData);
      setUploadedFile(result);
      setPreviewFile(result);
      setSuccess(`Γ£à "${result.fileName}" uploaded successfully!`);
      setFiles((prev) => [result, ...prev]);
    } catch (err: any) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const handleQuoteRequest = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!uploadedFile) return;
    setQuoteLoading(true);
    setError('');
    try {
      await quoteApi.request({
        designId: uploadedFile.id,
        ...quoteForm,
        infillDensity: parseInt(String(quoteForm.infillDensity)),
      });
      setQuoteSuccess('Quote request sent! Vendors will respond soon.');
    } catch (err: any) {
      setError(err.message);
    } finally {
      setQuoteLoading(false);
    }
  };

  const handleDeleteFile = async (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (!confirm('Are you sure you want to delete this file?')) return;
    try {
      await designApi.delete(id);
      setFiles(files.filter((f: any) => f.id !== id));
      if (uploadedFile?.id === id) {
        setUploadedFile(null);
        setPreviewFile(null);
      }
    } catch (err: any) {
      setError(err.message || 'Failed to delete file');
    }
  };

  const materials = ['PLA', 'ABS', 'PETG', 'TPU', 'Resin', 'Nylon'];

  // Size-based capability filter
  const maxBoundingDim = uploadedFile?.boundingBoxCm
    ? Math.max(uploadedFile.boundingBoxCm.length || 0, uploadedFile.boundingBoxCm.width || 0, uploadedFile.boundingBoxCm.height || 0)
    : 0;
  const filteredCategory = maxBoundingDim > 20 ? 'Large' : maxBoundingDim > 10 ? 'Medium' : 'Small';

  const capabilityFilteredVendors = vendors.filter(v => {
    if (!uploadedFile) return true;
    if (!v.capabilities || v.capabilities.length === 0) return true;
    return v.capabilities.includes(filteredCategory);
  });

  // Search filter on top of capability filter
  const searchedVendors = capabilityFilteredVendors.filter(v => {
    if (!vendorSearch.trim()) return true;
    const q = vendorSearch.toLowerCase();
    return (
      v.companyName?.toLowerCase().includes(q) ||
      v.location?.toLowerCase().includes(q)
    );
  });

  const localVendors = searchedVendors.filter((v: any) => v.isLocal);
  const otherVendors = searchedVendors.filter((v: any) => !v.isLocal);

  return (
    <div className="max-w-3xl mx-auto">
      <div className="mb-6">
        <h1 className="text-2xl font-bold text-white">Upload Design</h1>
        <p className="text-slate-400 text-sm mt-1">Upload your STL or OBJ file and request quotes from vendors</p>
      </div>

      {/* City Banner */}
      <div className="glass rounded-2xl p-4 mb-6 flex items-center gap-4">
        <span className="text-2xl">≡ƒôì</span>
        <div className="flex-1">
          {cityEditing ? (
            <div>
              <p className="text-xs text-slate-400 mb-1.5">Enter your city to see local vendors first</p>
              <div className="flex gap-2">
                <input
                  value={customerCity}
                  onChange={e => setCustomerCity(e.target.value)}
                  onKeyDown={e => e.key === 'Enter' && handleSaveCity()}
                  placeholder="e.g. Mumbai, Delhi, Bangalore..."
                  className="flex-1 px-3 py-2 rounded-xl bg-white/5 border border-white/10 text-white placeholder-slate-500 focus:outline-none focus:border-violet-500 text-sm"
                />
                <button
                  onClick={handleSaveCity}
                  disabled={savingCity || !customerCity.trim()}
                  className="px-4 py-2 rounded-xl bg-violet-600 hover:bg-violet-500 disabled:opacity-50 text-white text-sm font-medium transition-colors"
                >
                  {savingCity ? 'Saving...' : 'Save'}
                </button>
              </div>
            </div>
          ) : (
            <div className="flex items-center justify-between">
              <div>
                <p className="text-xs text-slate-400">Your city</p>
                <p className="text-white font-medium">{customerCity}</p>
              </div>
              <button
                onClick={() => setCityEditing(true)}
                className="text-xs text-violet-400 hover:text-violet-300"
              >
                Change
              </button>
            </div>
          )}
        </div>
      </div>

      {/* Drop Zone */}
      <div
        onDragOver={(e) => { e.preventDefault(); setDragging(true); }}
        onDragLeave={() => setDragging(false)}
        onDrop={handleDrop}
        className={`relative border-2 border-dashed rounded-2xl p-12 text-center transition-all cursor-pointer ${
          dragging
            ? 'border-violet-500 bg-violet-500/10'
            : 'border-white/10 hover:border-violet-500/50 hover:bg-white/[0.02]'
        }`}
        onClick={() => document.getElementById('fileInput')?.click()}
      >
        <input
          id="fileInput"
          type="file"
          accept=".stl,.obj"
          className="hidden"
          onChange={(e) => e.target.files?.[0] && handleUpload(e.target.files[0])}
        />
        {loading ? (
          <div className="flex flex-col items-center gap-3">
            <div className="w-10 h-10 spinner" />
            <p className="text-slate-400">Uploading to cloud...</p>
          </div>
        ) : (
          <>
