'use client';

import { useState, useEffect } from 'react';
import { paymentApi } from '@/lib/api';
import Image from 'next/image';

interface EarningRecord {
  id: string;
  orderId: string;
  amount: number;
  vendorAmount: number;
  platformFee: number;
  gst: number;
  commissionRate: number;
  status: string;
  escrowReleasesAt: string | null;
  releasedAt: string | null;
  createdAt: string;
  vendorSettlementAmount?: number;
  platformSettlementAmount?: number;
}

const STATUS_CONFIG: Record<string, { label: string; color: string; bg: string }> = {
  ESCROWED:           { label: 'ΓÅ│ In Escrow',     color: 'text-amber-400',  bg: 'bg-amber-900/30 border-amber-500/30' },
  RELEASED:           { label: 'Γ£à Paid Out',       color: 'text-green-400',  bg: 'bg-green-900/30 border-green-500/30' },
  FROZEN:             { label: '≡ƒöÆ Frozen',         color: 'text-red-400',    bg: 'bg-red-900/30 border-red-500/30' },
  REFUNDED:           { label: 'Γå⌐∩╕Å Refunded',       color: 'text-purple-400', bg: 'bg-purple-900/30 border-purple-500/30' },
  PARTIALLY_REFUNDED: { label: 'ΓÜá∩╕Å Part Refunded',  color: 'text-orange-400', bg: 'bg-orange-900/30 border-orange-500/30' },
  PENDING:            { label: '≡ƒòÉ Pending',        color: 'text-slate-400',  bg: 'bg-slate-800 border-slate-700' },
};

function EscrowCountdown({ releasesAt }: { releasesAt: string }) {
  const [timeLeft, setTimeLeft] = useState('');

  useEffect(() => {
    const update = () => {
      const ms = new Date(releasesAt).getTime() - Date.now();
      if (ms <= 0) { setTimeLeft('Releasing soon...'); return; }
      const h = Math.floor(ms / (1000 * 60 * 60));
      const m = Math.floor((ms % (1000 * 60 * 60)) / (1000 * 60));
      setTimeLeft(`${h}h ${m}m remaining`);
    };
    update();
    const interval = setInterval(update, 60000);
    return () => clearInterval(interval);
  }, [releasesAt]);

  return <span className="text-amber-400 text-xs">{timeLeft}</span>;
}

