    const fd = new FormData();
    fd.append('logo', file);
    try {
      const res = await vendorApi.uploadLogo(fd);
      setLogoUrl(res.logoUrl);
      setMessage({ type: 'success', text: 'Company logo updated!' });
      setTimeout(() => setMessage({ type: '', text: '' }), 3000);
