  useEffect(() => {
    authApi.me().then((data: any) => {
      const v = data?.vendor;
      setForm({
        companyName: v?.companyName || data?.name || '',
        city: v?.location || '',
        state: v?.state || '',
        pincode: v?.pincode || '',
