                    Remove Logo
                  </button>
                )}
              </div>
            </div>

            {/* Account Info */}
            <div className="glass rounded-3xl p-6 space-y-4">
              <div className="flex items-center gap-4">
                <div className="w-10 h-10 rounded-xl bg-white/5 flex items-center justify-center">
                  <Mail className="w-5 h-5 text-slate-400" />
