                    </motion.button>
                  );
                })}
              </div>

              {/* Scroll hints */}
              <div className="absolute left-0 top-0 bottom-6 w-12 bg-gradient-to-r from-[#0a0a0f] to-transparent pointer-events-none opacity-0 group-hover/scroll:opacity-100 transition-opacity" />
