            <div className="flex items-center justify-center h-64">
              <div className="w-10 h-10 spinner" />
            </div>
          ) : products.length === 0 ? (
            <div className="glass rounded-2xl p-16 text-center">
              <div className="text-5xl mb-4">{activeCat?.emoji || '≡ƒÅ¬'}</div>
