          ) : (
            <div className="text-center py-12">
              <p className="text-4xl mb-3">≡ƒöÆ</p>
              <p className="text-slate-400 text-sm">Log in as a customer to rate this vendor.</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

